class Solution:
    def minEnergy(self, n: int, brightness: int, intervals) -> int:
        minBulbs = (brightness + 2) // 3
        ivs = sorted(intervals)
        total = 0
        curS, curE = ivs[0]
        for s, e in ivs[1:]:
            if s <= curE:
                if e > curE:
                    curE = e
            else:
                total += curE - curS + 1
                curS, curE = s, e
        total += curE - curS + 1
        return minBulbs * total

