var minEnergy = function(n, brightness, intervals) {
    const minBulbs = Math.floor((brightness + 2) / 3);
    const ivs = intervals.slice().sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    let total = 0;
    let curS = ivs[0][0], curE = ivs[0][1];
    for (let i = 1; i < ivs.length; i++) {
        const s = ivs[i][0], e = ivs[i][1];
        if (s <= curE) {
            if (e > curE) curE = e;
        } else {
            total += curE - curS + 1;
            curS = s; curE = e;
        }
    }
    total += curE - curS + 1;
    return minBulbs * total;
};
